import { useEffect, useMemo, useRef, useState } from "react";
import type { AllocatorState, Participant, Reason } from "./types";
import { allocate, applyRoles } from "./allocator";

const INITIAL: Participant[] = [
  { id: "p1", name: "Sara",   bid: 0.30, reason: "build-on",   budgetSec: 240, role: "speaker" },
  { id: "p2", name: "Devraj", bid: 0.62, reason: "disagree",   budgetSec: 280, role: "on-deck" },
  { id: "p3", name: "Mei",    bid: 0.10, reason: "question",   budgetSec: 295, role: "idle" },
  { id: "p4", name: "Tom",    bid: 0.45, reason: "build-on",   budgetSec: 200, role: "idle" },
  { id: "p5", name: "Aida",   bid: 0.05, reason: "time-check", budgetSec: 290, role: "idle" },
];

const REASONS: Reason[] = ["question", "disagree", "build-on", "time-check"];

export function App() {
  const [participants, setParticipants] = useState<Participant[]>(INITIAL);
  const [state, setState] = useState<AllocatorState>({
    meetingMode: "decide",
    speakerHeldSec: 0,
    softTurnCapSec: 30,
  });
  const [autoTick, setAutoTick] = useState(true);
  const [lastReasons, setLastReasons] = useState<Record<string, string>>({});
  const speakerStartRef = useRef<number>(Date.now());
  const currentSpeakerId = participants.find((p) => p.role === "speaker")?.id ?? null;

  // 5 Hz tick: re-run allocation, age budgets, age speaker hold.
  useEffect(() => {
    if (!autoTick) return;
    const id = window.setInterval(() => {
      setParticipants((prev) => {
        // age speaker budget at 1s per 5 ticks (since we tick at 5Hz)
        const aged = prev.map((p) =>
          p.role === "speaker" ? { ...p, budgetSec: Math.max(0, p.budgetSec - 0.2) } : p,
        );
        const heldSec = (Date.now() - speakerStartRef.current) / 1000;
        const result = allocate(aged, { ...state, speakerHeldSec: heldSec }, currentSpeakerId);
        setLastReasons(result.reasons);
        if (result.speakerId !== currentSpeakerId) {
          speakerStartRef.current = Date.now();
        }
        return applyRoles(aged, result.speakerId, result.onDeckId);
      });
    }, 200);
    return () => window.clearInterval(id);
  }, [autoTick, state, currentSpeakerId]);

  // keep the held-sec readout fresh outside of the tick
  const [now, setNow] = useState(Date.now());
  useEffect(() => {
    const id = window.setInterval(() => setNow(Date.now()), 100);
    return () => window.clearInterval(id);
  }, []);
  const heldSec = (now - speakerStartRef.current) / 1000;
  const pressure = Math.min(1, Math.max(0, (heldSec - state.softTurnCapSec) / state.softTurnCapSec));

  const sorted = useMemo(
    () =>
      [...participants].sort((a, b) => {
        const order = { speaker: 0, "on-deck": 1, idle: 2 } as const;
        return order[a.role] - order[b.role] || b.bid - a.bid;
      }),
    [participants],
  );

  function setBid(id: string, bid: number) {
    setParticipants((prev) => prev.map((p) => (p.id === id ? { ...p, bid } : p)));
  }
  function setReason(id: string, reason: Reason) {
    setParticipants((prev) => prev.map((p) => (p.id === id ? { ...p, reason } : p)));
  }

  return (
    <div className="app">
      <header>
        <h1>Antiphon · bid heat-map</h1>
        <div className="controls">
          <label>
            mode:
            <select
              value={state.meetingMode}
              onChange={(e) => setState((s) => ({ ...s, meetingMode: e.target.value as AllocatorState["meetingMode"] }))}
            >
              {["brainstorm", "decide", "inform", "socialize"].map((m) => (
                <option key={m}>{m}</option>
              ))}
            </select>
          </label>
          <label>
            soft turn cap (s):
            <input
              type="number"
              min={5}
              max={300}
              value={state.softTurnCapSec}
              onChange={(e) => setState((s) => ({ ...s, softTurnCapSec: Number(e.target.value) }))}
            />
          </label>
          <label>
            <input type="checkbox" checked={autoTick} onChange={(e) => setAutoTick(e.target.checked)} /> auto-tick (5 Hz)
          </label>
        </div>
        <div className="stage-readout">
          held: <strong>{heldSec.toFixed(1)}s</strong> · cap: {state.softTurnCapSec}s · handoff pressure:{" "}
          <span style={{ color: pressure > 0.5 ? "#ff5a5a" : "#7c7" }}>{(pressure * 100).toFixed(0)}%</span>
        </div>
      </header>

      <main>
        {sorted.map((p) => (
          <article key={p.id} className={`participant role-${p.role}`}>
            <div className="row top">
              <div className="name">{p.name}</div>
              <div className="role-pill">{p.role}</div>
              <div className="budget">budget {p.budgetSec.toFixed(0)}s</div>
            </div>

            <div className="bid-row">
              <div className="bid-bar-wrap" title="continuous bid intensity (public)">
                <div className={`bid-bar reason-${p.reason}`} style={{ width: `${p.bid * 100}%` }} />
              </div>
              <input
                type="range"
                min={0}
                max={1}
                step={0.01}
                value={p.bid}
                onChange={(e) => setBid(p.id, Number(e.target.value))}
              />
              <span className="bid-num">{p.bid.toFixed(2)}</span>
            </div>

            <div className="reasons">
              {REASONS.map((r) => (
                <button
                  key={r}
                  className={`reason-pill reason-${r} ${p.reason === r ? "active" : ""}`}
                  onClick={() => setReason(p.id, r)}
                >
                  {r}
                </button>
              ))}
            </div>

            {lastReasons[p.id] && <div className="why">{lastReasons[p.id]}</div>}
          </article>
        ))}
      </main>

      <footer>
        <small>
          decorators stack — see <code>docs/antiphon.md</code> §Embrace. policy weights live in{" "}
          <code>src/allocator.ts</code>. quiet-bidder boost is the DiMicco 2004 caveat fix.
        </small>
      </footer>
    </div>
  );
}

