const heldSec = (now - speakerStartRef.current) / 1000;
const pressure = Math.min(1, Math.max(0, (heldSec - state.softTurnCapSec) / state.softTurnCapSec));

// Private countdown overlays. These are what the v1 product ships
// instead of hard mic control — see ADR 0003.
const countdown: Countdown | null = useMemo(() => {
  // estimated seconds remaining until handoff = (1 - pressure) * softTurnCapSec
  // (rough: pressure 0 -> full cap left; pressure 1 -> 0 left)
  const handoffEta = Math.max(0, (1 - pressure) * state.softTurnCapSec);
  if (seatId === currentSpeakerId && pressure > 0.4) {
    return {
      forParticipantId: seatId,
      kind: "wrap-soon",
      secondsRemaining: handoffEta,
      hint: "two strong bids waiting · wrap soon",
    };
  }
  if (seatId === onDeckId) {
    return {
      forParticipantId: seatId,
      kind: "unmute-soon",
      secondsRemaining: handoffEta,
      hint: "you're up next · unmute now",
    };
  }
  return null;
}, [seatId, currentSpeakerId, onDeckId, pressure, state.softTurnCapSec]);

