:root {
  --bg: #0c0f14;
  --panel: #151a22;
  --panel-2: #1b212c;
  --ink: #e7ecf3;
  --ink-dim: #93a0b3;
  --accent: #7cd3ff;
  --speaker: #ffd95e;
  --on-deck: #c5a8ff;

  --reason-question: #5cc2ff;
  --reason-disagree: #ff6c6c;
  --reason-build-on: #6cd07f;
  --reason-time-check: #f1a04a;

  font-family: ui-sans-serif, system-ui, -apple-system, "Segoe UI", Roboto, sans-serif;
  color-scheme: dark;
}

* { box-sizing: border-box; }

html, body, #root { height: 100%; }
body {
  margin: 0;
  background: radial-gradient(circle at 20% 0%, #1a2230 0%, var(--bg) 60%);
  color: var(--ink);
}

.app {
  max-width: 880px;
  margin: 0 auto;
  padding: 24px 20px 60px;
}

header {
  display: flex;
  flex-direction: column;
  gap: 8px;
  padding-bottom: 18px;
  border-bottom: 1px solid #232a36;
  margin-bottom: 18px;
}
h1 { margin: 0; font-size: 20px; letter-spacing: 0.02em; font-weight: 600; }
.controls {
  display: flex; flex-wrap: wrap; gap: 14px; align-items: center;
  font-size: 13px; color: var(--ink-dim);
}
.controls label { display: inline-flex; gap: 6px; align-items: center; }
.controls select, .controls input[type=number] {
  background: var(--panel-2); color: var(--ink);
  border: 1px solid #2a323f; border-radius: 6px; padding: 4px 8px;
  font-size: 13px;
}
.stage-readout { font-size: 13px; color: var(--ink-dim); }
.stage-readout strong { color: var(--ink); }

main { display: flex; flex-direction: column; gap: 10px; }

.participant {
  background: var(--panel);
  border: 1px solid #232a36;
  border-radius: 10px;
  padding: 10px 14px;
  transition: opacity 200ms, transform 200ms, border-color 200ms;
}
.participant.role-speaker {
  border-color: var(--speaker);
  background: linear-gradient(180deg, rgba(255,217,94,0.07), transparent), var(--panel);
  transform: scale(1.01);
}
.participant.role-on-deck {
  border-color: var(--on-deck);
  background: linear-gradient(180deg, rgba(197,168,255,0.05), transparent), var(--panel);
}
.participant.role-idle { opacity: 0.7; }

.row.top { display: flex; align-items: baseline; gap: 12px; margin-bottom: 6px; }
.name { font-weight: 600; font-size: 15px; }
.role-pill {
  font-size: 11px; padding: 2px 8px; border-radius: 999px;
  background: #232a36; color: var(--ink-dim); text-transform: uppercase; letter-spacing: 0.04em;
}
.role-speaker .role-pill { background: var(--speaker); color: #1a1300; }
.role-on-deck .role-pill { background: var(--on-deck); color: #1c0d39; }
.budget { margin-left: auto; font-size: 12px; color: var(--ink-dim); font-variant-numeric: tabular-nums; }

.bid-row { display: grid; grid-template-columns: 1fr 180px 40px; gap: 10px; align-items: center; margin: 6px 0 8px; }
.bid-bar-wrap {
  height: 10px; background: #0e131b; border-radius: 5px; overflow: hidden;
  border: 1px solid #232a36;
}
.bid-bar { height: 100%; transition: width 200ms ease-out; }
.bid-bar.reason-question  { background: var(--reason-question); }
.bid-bar.reason-disagree  { background: var(--reason-disagree); }
.bid-bar.reason-build-on  { background: var(--reason-build-on); }
.bid-bar.reason-time-check { background: var(--reason-time-check); }

.bid-row input[type=range] { width: 100%; accent-color: var(--accent); }
.bid-num { font-variant-numeric: tabular-nums; font-size: 12px; color: var(--ink-dim); text-align: right; }

.reasons { display: flex; gap: 6px; flex-wrap: wrap; }
.reason-pill {
  font-size: 12px; padding: 4px 9px; border-radius: 999px;
  background: transparent; color: var(--ink-dim);
  border: 1px solid #2a323f; cursor: pointer;
  transition: background 120ms, color 120ms, border-color 120ms;
}
.reason-pill:hover { color: var(--ink); }
.reason-pill.reason-question.active  { background: var(--reason-question); color: #001220; border-color: var(--reason-question); }
.reason-pill.reason-disagree.active  { background: var(--reason-disagree); color: #220000; border-color: var(--reason-disagree); }
.reason-pill.reason-build-on.active  { background: var(--reason-build-on); color: #003a10; border-color: var(--reason-build-on); }
.reason-pill.reason-time-check.active { background: var(--reason-time-check); color: #2b1500; border-color: var(--reason-time-check); }

.why {
  margin-top: 8px; font-size: 11px; color: var(--ink-dim);
  font-family: ui-monospace, SFMono-Regular, Menlo, monospace;
  background: #0e131b; border: 1px solid #232a36; border-radius: 6px;
  padding: 6px 8px; overflow-x: auto; white-space: pre;
}

footer { margin-top: 28px; color: var(--ink-dim); font-size: 12px; }
footer code { background: #232a36; padding: 1px 5px; border-radius: 4px; color: var(--ink); }

