// GainScope describes which participants this adapter can control.
type GainScope int

const (
	GainScopeNone       GainScope = iota // view-only — allocator runs in advisory mode
	GainScopeLocalOnly                   // relay adapters: can only gate the local user
	GainScopeAll                         // native / bot-as-host adapters
)

// GainPolarity is asymmetric: we may have authority to mute but not unmute.
// Unmuting someone surprises them onto-air — too invasive for a v1 nudge
// product. Hard-muting a floor-hogger past the soft cap is the
// high-value enforcement case (human moderators avoid it because of the
// social cost; the AI doesn't carry that cost). See ADR 0003.
type GainPolarity int

const (
	GainPolarityAdvisory GainPolarity = iota // SetGain is a hint; UI countdown is the actual signal
	GainPolarityMuteOnly                     // can drive gain to 0; cannot raise above current
	GainPolarityFull                         // both directions
)

