export type Reason = "question" | "disagree" | "build-on" | "time-check";

export type Role = "speaker" | "on-deck" | "idle";

export interface Participant {
  id: string;
  name: string;
  // continuous bid intensity, [0, 1]
  bid: number;
  // current reason tag attached to the bid
  reason: Reason;
  // seconds of speaking budget remaining this meeting
  budgetSec: number;
  // assigned floor role — updated by the allocator on each tick
  role: Role;
}

export interface AllocatorState {
  meetingMode: "brainstorm" | "decide" | "inform" | "socialize";
  // wall-clock seconds the current speaker has held the floor
  speakerHeldSec: number;
  // soft cap for any single turn; allocator pressures handoff past this
  softTurnCapSec: number;
}

// Countdown is the private HUD nudge for a single participant.
// The product's advisory enforcement layer (no hard mic control in v1).
export interface Countdown {
  forParticipantId: string;
  kind: "unmute-soon" | "wrap-soon" | "recruit";
  // monotonic seconds remaining until the predicted action.
  // negative values are allowed for "overdue"; UI clamps display.
  secondsRemaining: number;
  // human-readable hint shown alongside the countdown digits
  hint: string;
}

