// Countdown is the private HUD nudge for a single participant.
// The product's advisory enforcement layer (no hard mic control in v1).
//
// `tier` is the escalation step (panel finding: without hard mute, the
// only enforcement is visibility — graduate the social pressure).
// notice -> nudge -> warn -> over.
export type CountdownTier = "notice" | "nudge" | "warn" | "over";

export interface Countdown {
  forParticipantId: string;
  kind: "unmute-soon" | "wrap-soon" | "recruit";
  tier: CountdownTier;
  // Seconds remaining until the predicted action.
  // Computed by the spike against Date.now(); real product needs
  // server-monotonic deadlineServerMs + per-client NTP offset (see
  // ADR 0004 realtime panel). Without that, multi-participant
  // countdowns desync by ±50-500ms across browsers.
  secondsRemaining: number;
  // TODO(v1): replace Date.now() math with deadlineServerMs delivered
  // by the WebSocket fanout, rendered as `deadlineServerMs - (now + offset)`
  // where `offset` is estimated from WS-ping round-trips.
  deadlineServerMs?: number;
  hint: string;
}

// PublicEscalation is what every participant sees about the *current
// speaker* when they overrun. This is the "increasingly passively
// obvious they should shut up" layer: no mute, just visibility ramps.
// Same tier scale as Countdown. The speaker's card UI reads this and
// tints / pulses / banners accordingly.
export interface PublicEscalation {
  speakerId: string;
  tier: CountdownTier;
}

