  // by the WebSocket fanout, rendered as `deadlineServerMs - (now + offset)`
  // where `offset` is estimated from WS-ping round-trips.
  deadlineServerMs?: number;
  hint: string;
}

// PublicEscalation is what every participant sees about the *current
// speaker* when they overrun. This is the "increasingly passively
// obvious they should shut up" layer: no mute, just visibility ramps.
// Same tier scale as Countdown. The speaker's card UI reads this and
// tints / pulses / banners accordingly.
export interface PublicEscalation {
  speakerId: string;
  tier: CountdownTier;
}

