// ---- Radial bid menu state ----
const [radialOpen, setRadialOpen] = useState(false);
const self = participants.find((p) => p.id === seatId);
const openRadial = useCallback(() => setRadialOpen(true), []);
const closeRadial = useCallback(() => setRadialOpen(false), []);
const onRadialCommit = useCallback((c: RadialCommit | null) => {
  if (!c) return; // cancel: leave bid unchanged
  setParticipants((prev) =>
    prev.map((p) => (p.id === seatId ? { ...p, bid: c.intensity, reason: c.reason } : p)),
  );
}, [seatId]);
// Global Space-hold opens the radial. Space-release commits (handled inside Radial).
// We ignore Space when it's inside an input/select.
useEffect(() => {
  function onKey(e: KeyboardEvent) {
    if (e.code !== "Space" && e.key !== "b") return;
    const target = e.target as HTMLElement | null;
    const tag = target?.tagName;
    if (tag === "INPUT" || tag === "SELECT" || tag === "TEXTAREA") return;
    if (e.repeat) return;
    if (radialOpen) return;
    e.preventDefault();
    setRadialOpen(true);
  }
  window.addEventListener("keydown", onKey);
  return () => window.removeEventListener("keydown", onKey);
}, [radialOpen]);

