/* Radial bid menu (user's idea: hold-Space or hold-button, mouse drag or
   keyboard, angle = reason, distance = intensity, hard-snap at 72° wedges). */
.radial-backdrop {
  position: fixed;
  inset: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  background: rgba(8, 11, 16, 0.72);
  backdrop-filter: blur(4px);
  z-index: 100;
  cursor: crosshair;
}
.radial-wrap {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 12px;
}
.radial-help {
  font-size: 16px;
  font-weight: 600;
  color: var(--ink);
  letter-spacing: 0.02em;
  margin-top: 4px;
}
.radial-hint {
  font-size: 12px;
  color: var(--ink-dim);
  text-align: center;
  max-width: 520px;
  line-height: 1.5;
}
.radial-hint kbd {
  background: var(--panel-2);
  border: 1px solid #2a323f;
  border-radius: 4px;
  padding: 1px 6px;
  margin: 0 2px;
  font-size: 11px;
  font-family: ui-monospace, SFMono-Regular, Menlo, monospace;
  color: var(--ink);
}
.radial-trigger {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  margin-top: 10px;
  padding: 8px 14px;
  background: var(--accent);
  color: #001220;
  border: none;
  border-radius: 8px;
  font-size: 13px;
  font-weight: 700;
  letter-spacing: 0.02em;
  cursor: pointer;
  user-select: none;
  transition: filter 120ms, transform 60ms;
}
.radial-trigger:hover { filter: brightness(1.08); }
.radial-trigger:active { transform: scale(0.97); }
.kbd-hint {
  background: rgba(0, 18, 32, 0.25);
  border: 1px solid rgba(0, 18, 32, 0.4);
  border-radius: 4px;
  padding: 1px 6px;
  font-size: 10px;
  font-family: ui-monospace, SFMono-Regular, Menlo, monospace;
  font-weight: 600;
  letter-spacing: 0.06em;
  text-transform: uppercase;
}

/* PUBLIC overrun banner — top-of-page, visible to all participants when
   the speaker is past their turn (tier 'over'). */

