raw.originalFile:
:root {
  --bg: #0c0f14;
  --panel: #151a22;
  --panel-2: #1b212c;
  --ink: #e7ecf3;
  --ink-dim: #93a0b3;
  --accent: #7cd3ff;
  --speaker: #ffd95e;
  --on-deck: #c5a8ff;

  --reason-question: #5cc2ff;
  --reason-disagree: #ff6c6c;
  --reason-build-on: #6cd07f;
  --reason-time-check: #f1a04a;
  --reason-repair: #e36cd0;

  --tier-notice: #7c7;
  --tier-nudge: #f1a04a;
  --tier-warn: #ff7a3a;
  --tier-over: #ff3a3a;

  font-family: ui-sans-serif, system-ui, -apple-system, "Segoe UI", Roboto, sans-serif;
  color-scheme: dark;
}

* { box-sizing: border-box; }

html, body, #root { height: 100%; }
body {
  margin: 0;
  background: radial-gradient(circle at 20% 0%, #1a2230 0%, var(--bg) 60%);
  color: var(--ink);
}

.app {
  max-width: 880px;
  margin: 0 auto;
  padding: 24px 20px 60px;
}

header {
  display: flex;
  flex-direction: column;
  gap: 8px;
  padding-bottom: 18px;
  border-bottom: 1px solid #232a36;
  margin-bottom: 18px;
}
h1 { margin: 0; font-size: 20px; letter-spacing: 0.02em; font-weight: 600; }
.controls {
  display: flex; flex-wrap: wrap; gap: 14px; align-items: center;
  font-size: 13px; color: var(--ink-dim);
}
.controls label { display: inline-flex; gap: 6px; align-items: center; }
.controls select, .controls input[type=number] {
  background: var(--panel-2); color: var(--ink);
  border: 1px solid #2a323f; border-radius: 6px; padding: 4px 8px;
  font-size: 13px;
}
.stage-readout { font-size: 13px; color: var(--ink-dim); }
.stage-readout strong { color: var(--ink); }
.tier-pill {
  display: inline-block;
  padding: 1px 8px;
  border-radius: 999px;
  font-size: 11px;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.04em;
  margin-left: 6px;
}
.tier-pill.tier-notice { background: rgba(124, 200, 124, 0.18); color: var(--tier-notice); }
.tier-pill.tier-nudge  { background: rgba(241, 160, 74, 0.20); color: var(--tier-nudge); }
.tier-pill.tier-warn   { background: rgba(255, 122, 58, 0.22); color: var(--tier-warn); }
.tier-pill.tier-over   { background: var(--tier-over); color: #fff; }

main { display: flex; flex-direction: column; gap: 10px; }

.participant {
  background: var(--panel);
  border: 1px solid #232a36;
  border-radius: 10px;
  padding: 10px 14px;
  transition: opacity 200ms, transform 200ms, border-color 200ms, background 200ms, box-shadow 200ms;
}
.participant.role-speaker {
  border-color: var(--speaker);
  background: linear-gradient(180deg, rgba(255,217,94,0.07), transparent), var(--panel);
  transform: scale(1.01);
}
.participant.role-on-deck {
  border-color: var(--on-deck);
  background: linear-gradient(180deg, rgba(197,168,255,0.05), transparent), var(--panel);
}
.participant.role-idle { opacity: 0.7; }

/* Public escalation — what the WHOLE ROOM sees on the speaker when they overrun.
   The user's "increasingly passively obvious they should shut up" lever. */
.participant.escalate-nudge {
  background: linear-gradient(180deg, rgba(241, 160, 74, 0.12), transparent), var(--panel);
  border-color: var(--tier-nudge);
}
.participant.escalate-warn {
  background: linear-gradient(180deg, rgba(255, 122, 58, 0.22), transparent), var(--panel);
  border-color: var(--tier-warn);
  box-shadow: 0 0 0 1px var(--tier-warn);
  animation: warn-pulse 1200ms ease-in-out infinite alternate;
}
.participant.escalate-over {
  background: linear-gradient(180deg, rgba(255, 58, 58, 0.30), transparent), var(--panel);
  border-color: var(--tier-over);
  box-shadow: 0 0 0 2px var(--tier-over), 0 0 28px rgba(255, 58, 58, 0.5);
  animation: over-pulse 700ms ease-in-out infinite alternate;
}
@keyframes warn-pulse {
  from { box-shadow: 0 0 0 1px var(--tier-warn), 0 0 0 rgba(255,122,58,0); }
  to   { box-shadow: 0 0 0 1px var(--tier-warn), 0 0 18px rgba(255,122,58,0.45); }
}
@keyframes over-pulse {
  from { box-shadow: 0 0 0 2px var(--tier-over), 0 0 18px rgba(255,58,58,0.4); }
  to   { box-shadow: 0 0 0 2px var(--tier-over), 0 0 36px rgba(255,58,58,0.85); }
}

.row.top { display: flex; align-items: baseline; gap: 12px; margin-bottom: 6px; }
.name { font-weight: 600; font-size: 15px; }
.you-tag { color: var(--accent); font-weight: 500; font-size: 12px; margin-left: 6px; }
.role-pill {
  font-size: 11px; padding: 2px 8px; border-radius: 999px;
  background: #232a36; color: var(--ink-dim); text-transform: uppercase; letter-spacing: 0.04em;
}
.role-speaker .role-pill { background: var(--speaker); color: #1a1300; }
.role-on-deck .role-pill { background: var(--on-deck); color: #1c0d39; }
.budget { margin-left: auto; font-size: 12px; color: var(--ink-dim); font-variant-numeric: tabular-nums; }

.bid-row { display: grid; grid-template-columns: 1fr 180px 40px; gap: 10px; align-items: center; margin: 6px 0 8px; }
.bid-bar-wrap {
  height: 10px; background: #0e131b; border-radius: 5px; overflow: hidden;
  border: 1px solid #232a36;
}
.bid-bar { height: 100%; transition: width 200ms ease-out; }
.bid-bar.reason-question  { background: var(--reason-question); }
.bid-bar.reason-disagree  { background: var(--reason-disagree); }
.bid-bar.reason-build-on  { background: var(--reason-build-on); }
.bid-bar.reason-time-check { background: var(--reason-time-check); }
.bid-bar.reason-repair    { background: var(--reason-repair); }

.bid-row input[type=range] { width: 100%; accent-color: var(--accent); }
.bid-num { font-variant-numeric: tabular-nums; font-size: 12px; color: var(--ink-dim); text-align: right; }

.reasons { display: flex; gap: 6px; flex-wrap: wrap; }
.reason-pill {
  font-size: 12px; padding: 4px 9px; border-radius: 999px;
  background: transparent; color: var(--ink-dim);
  border: 1px solid #2a323f; cursor: pointer;
  transition: background 120ms, color 120ms, border-color 120ms;
}
.reason-pill:hover { color: var(--ink); }
.reason-pill.reason-question.active  { background: var(--reason-question); color: #001220; border-color: var(--reason-question); }
.reason-pill.reason-disagree.active  { background: var(--reason-disagree); color: #220000; border-color: var(--reason-disagree); }
.reason-pill.reason-build-on.active  { background: var(--reason-build-on); color: #003a10; border-color: var(--reason-build-on); }
.reason-pill.reason-time-check.active { background: var(--reason-time-check); color: #2b1500; border-color: var(--reason-time-check); }
.reason-pill.reason-repair.active    { background: var(--reason-repair); color: #2b0028; border-color: var(--reason-repair); }

.why {
  margin-top: 8px; font-size: 11px; color: var(--ink-dim);
  font-family: ui-monospace, SFMono-Regular, Menlo, monospace;
  background: #0e131b; border: 1px solid #232a36; border-radius: 6px;
  padding: 6px 8px; overflow-x: auto; white-space: pre;
}

footer { margin-top: 28px; color: var(--ink-dim); font-size: 12px; }
footer code { background: #232a36; padding: 1px 5px; border-radius: 4px; color: var(--ink); }

/* Private countdown overlay — graduated tier urgency. */
.countdown {
  position: fixed;
  top: 16px;
  right: 16px;
  display: flex;
  gap: 14px;
  align-items: center;
  padding: 12px 16px;
  border-radius: 12px;
  background: var(--panel-2);
  border: 1px solid #2a323f;
  box-shadow: 0 8px 32px rgba(0,0,0,0.4);
  z-index: 10;
  min-width: 240px;
  transition: border-color 200ms, background 200ms, box-shadow 200ms;
}
.countdown.tier-notice { /* default */ }
.countdown.tier-nudge  { border-color: var(--tier-nudge); }
.countdown.tier-warn   { border-color: var(--tier-warn); animation: warn-pulse 1200ms ease-in-out infinite alternate; }
.countdown.tier-over   {
  border-color: var(--tier-over);
  background: linear-gradient(180deg, rgba(255, 58, 58, 0.18), var(--panel-2));
  animation: over-pulse 700ms ease-in-out infinite alternate;
}
.countdown-unmute-soon { border-color: var(--on-deck); }
.countdown-wrap-soon   { border-color: var(--speaker); }
.countdown-recruit     { border-color: var(--accent); }
.countdown-num {
  font-size: 36px;
  font-weight: 700;
  font-variant-numeric: tabular-nums;
  color: var(--ink);
  min-width: 50px;
  text-align: center;
}
.countdown.tier-warn .countdown-num { color: var(--tier-warn); }
.countdown.tier-over .countdown-num { color: var(--tier-over); }
.countdown-unmute-soon .countdown-num { color: var(--on-deck); }
.countdown-wrap-soon .countdown-num   { color: var(--speaker); }
.countdown-body { display: flex; flex-direction: column; gap: 2px; }
.countdown-title {
  font-size: 13px;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.04em;
  color: var(--ink);
}
.countdown-hint {
  font-size: 12px;
  color: var(--ink-dim);
}

/* PUBLIC overrun banner — top-of-page, visible to all participants when
   the speaker is past their turn (tier 'over'). */
.public-overrun-banner {
  position: sticky;
  top: 0;
  z-index: 8;
  margin: -24px -20px 16px;
  padding: 10px 20px;
  background: var(--tier-over);
  color: #fff;
  font-weight: 600;
  font-size: 14px;
  text-align: center;
  letter-spacing: 0.02em;
  box-shadow: 0 4px 18px rgba(255, 58, 58, 0.45);
  animation: over-pulse 700ms ease-in-out infinite alternate;
}

