   keyboard, angle = reason, distance = intensity, hard-snap at 72° wedges). */
.radial-backdrop {
  position: fixed;
  inset: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  background: rgba(8, 11, 16, 0.72);
  backdrop-filter: blur(4px);
  z-index: 100;
  cursor: crosshair;
}
.radial-wrap {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 12px;
}
.radial-help {
  font-size: 16px;
  font-weight: 600;
  color: var(--ink);
  letter-spacing: 0.02em;
  margin-top: 4px;
}
.radial-hint {
  font-size: 12px;
  color: var(--ink-dim);
  text-align: center;
  max-width: 520px;
  line-height: 1.5;
