  background: var(--panel-2);
  border: 1px solid #2a323f;
  border-radius: 4px;
  padding: 1px 6px;
  margin: 0 2px;
  font-size: 11px;
  font-family: ui-monospace, SFMono-Regular, Menlo, monospace;
  color: var(--ink);
