// Mouse: while the radial is open, mouse moves update the bid.
//
// Mouseup behavior is mode-discriminating:
// - If the user actually moved the mouse (drag mode), mouseup commits.
// - If they only clicked-to-open and never dragged, mouseup is a no-op:
//   the radial stays open for keyboard input (this is the tap-open path
//   for a11y and for users who prefer keyboard inside the menu).
const movedRef = useRef(false);
useEffect(() => {
  if (!open) {
    movedRef.current = false;
    return;
  }
  function onMove(e: MouseEvent) {
    const rect = containerRef.current?.getBoundingClientRect();
    if (!rect) return;
    const cx = rect.left + rect.width / 2;
    const cy = rect.top + rect.height / 2;
    const dx = e.clientX - cx;
    const dy = e.clientY - cy;
    const dist = Math.sqrt(dx * dx + dy * dy);
    // 12px deadband: ignore microscopic jitter between the trigger click
    // and the user actually starting to drag.
    if (dist > 12) movedRef.current = true;
    const { reasonIdx: ri, intensity: it } = pointToBid(dx, dy);
    setMode("mouse");
    setReasonIdx(ri);
    setIntensity(it);
  }
  function onUp() {
    if (!movedRef.current) return; // tap-open: stay open
    commit();
  }
  window.addEventListener("mousemove", onMove);
  window.addEventListener("mouseup", onUp);
  return () => {
    window.removeEventListener("mousemove", onMove);
    window.removeEventListener("mouseup", onUp);
  };
}, [open, commit]);

