// Global 'b' tap opens the radial. We DON'T use Space — Space conflicts
// with page scroll, embedded video play/pause, OS search etc (audit fix).
// Right-click on the app surface also opens — power-user mouse path.
useEffect(() => {
  function onKey(e: KeyboardEvent) {
    if (e.key !== "b" && e.key !== "B") return;
    const target = e.target as HTMLElement | null;
    const tag = target?.tagName;
    if (tag === "INPUT" || tag === "SELECT" || tag === "TEXTAREA") return;
    if (e.repeat) return;
    if (radialOpen) return;
    e.preventDefault();
