args.new_string:
  // Map a (dx, dy) from center to {reasonIdx, intensity} where intensity
// is snapped to one of three zones (low/med/high). The 9-step intensity was
// Hick's-law overload (5 reasons × 9 levels = 45 combinations); 3 zones is
// the audit-pass simplification.
function pointToBid(dx: number, dy: number): { reasonIdx: number | null; intensity: number } {
  const dist = Math.sqrt(dx * dx + dy * dy);
  if (dist < INNER) return { reasonIdx: null, intensity: 0 };
  const raw = Math.min(1, (dist - INNER) / (RADIUS - INNER));
  // Three zones, hard-snapped: 0.33 / 0.66 / 1.0
  let intensity = 0.33;
  if (raw >= 0.66) intensity = 1.0;
  else if (raw >= 0.33) intensity = 0.66;
  // Angle, top=0°, clockwise.
  let ang = (Math.atan2(dy, dx) * 180) / Math.PI + 90;
  if (ang < 0) ang += 360;
  const wedgeArc = 360 / WEDGES.length;
  const idx = Math.floor(((ang + wedgeArc / 2) % 360) / wedgeArc);
  return { reasonIdx: idx % WEDGES.length, intensity };
}

