args.new_string:
/* Settings disclosure — kebab icon, collapsed by default. */
.settings-disclosure {
  position: relative;
}
.settings-disclosure > summary {
  list-style: none;
  cursor: pointer;
  user-select: none;
  width: 32px;
  height: 32px;
  border-radius: var(--radius-pill);
  display: inline-flex;
  align-items: center;
  justify-content: center;
  font-size: 18px;
  color: var(--ink-dim);
  transition: background 120ms, color 120ms;
}
.settings-disclosure > summary::-webkit-details-marker { display: none; }
.settings-disclosure > summary:hover { background: var(--panel-2); color: var(--ink); }
.settings-disclosure[open] > summary { background: var(--panel-2); color: var(--ink); }
.settings-disclosure[open] .controls {
  position: absolute;
  right: 0;
  top: 40px;
  background: var(--panel);
  border: 1px solid var(--panel-line);
  border-radius: var(--radius);
  box-shadow: var(--shadow-lift);
  padding: 14px 16px;
  display: flex;
  flex-direction: column;
  gap: 10px;
  min-width: 240px;
  z-index: 20;
}
.settings-disclosure .controls label {
  display: flex;
  flex-direction: column;
  gap: 4px;
  font-size: 12px;
  color: var(--ink-dim);
}
.settings-disclosure .controls label input[type=checkbox] {
  align-self: flex-start;
  margin-top: 2px;
}
.settings-disclosure .controls select,
.settings-disclosure .controls input[type=number] {
  background: var(--panel-2); color: var(--ink);
  border: 1px solid var(--panel-line);
  border-radius: var(--radius-sm);
  padding: 6px 10px;
  font-size: 13px;
  font-family: inherit;
}
.settings-mission-btn {
  margin-top: 4px;
  background: var(--accent-soft);
  color: var(--accent);
  border: none;
  border-radius: var(--radius-sm);
  padding: 8px 12px;
  font-size: 13px;
  font-weight: 500;
  cursor: pointer;
  font-family: inherit;
}
.settings-mission-btn:hover { background: rgba(106, 166, 255, 0.20); }

